def validate_edad(edad):
    if edad is None:
        return ("MISSING", "review")
    if not isinstance(edad, int):
        return ("BAD_TYPE", "reject")
    if edad < 0 or edad > 120:
        return ("OUT_OF_RANGE", "reject")
    if edad < 18:
        return ("NEEDS_REVIEW", "review")
    return ("OK", "accept")

