def decide(edad, region, allowed={"Lima", "Cusco", "Arequipa"}):
    reasons = []
    if edad is None:
        reasons.append("edad_missing")
    elif not isinstance(edad, int) or edad < 18:
        reasons.append("edad_review_or_bad")
    if region is None or region not in allowed:
        reasons.append("region_review")
    if reasons:
        return "review", reasons
    return "accept", ["OK"]

print(decide(30, "Lima"))
print(decide(None, "Lima"))
print(decide(30, "Tacna"))

def score_row(row):
    score = 100
    reasons = []
    if row.get("edad") is None:
        score -= 30
        reasons.append("missing_edad")
    if row.get("region") not in {"Lima", "Cusco"}:
        score -= 20
        reasons.append("region")
    status = "accept" if score >= 80 else ("review" if score >= 50 else "reject")
    return {"score": score, "status": status, "reasons": reasons}

print(score_row({"edad": 30, "region": "Lima"}))
print(score_row({"edad": None, "region": "Tacna"}))
